-- {"operators": "OUTER_JOIN,AGGREGATE,ORDER,WINDOW,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "WAREHOUSE,DISTRICT,CUSTOMER,OORDER", "ducklake": true}
WITH cust_o AS (SELECT w.W_ID, d.D_ID, c.C_ID, COUNT(o.O_ID) AS n_orders FROM dl.WAREHOUSE w JOIN dl.DISTRICT d ON w.W_ID = d.D_W_ID JOIN dl.CUSTOMER c ON d.D_W_ID = c.C_W_ID AND d.D_ID = c.C_D_ID LEFT JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID GROUP BY w.W_ID, d.D_ID, c.C_ID) SELECT W_ID, D_ID, C_ID, n_orders, RANK() OVER (PARTITION BY W_ID ORDER BY n_orders DESC) AS r FROM cust_o;
